        if(!rst_n) begin
            // 리셋 조건이 활성화되었을 때, 모든 레지스터 초기화
            src_addr <= 32'b0;
            dst_addr <= 32'b0;
            byte_len <= 16'b0;
        end
        else if(wren) begin
            // 쓰기 동작을 핸들링
            case(paddr_i)
                12'h000: src_addr <= pwdata_i;  // 소스 주소 레지스터
                12'h004: dst_addr <= pwdata_i;  // 대상 주소 레지스터
                12'h008: byte_len <= pwdata_i[15:0];  // 바이트 길이 레지스터
                // 적절한 주소를 위해 더 많은 케이스를 추가할 수 있음
            endcase
        end
    end

    // DMA 시작 명령은 DMA_CMD 레지스터에 1을 쓸 때 활성화됩니다.
    reg start_reg;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            start_reg <= 0;
        else if (wren && paddr_i == 12'h00C && pwdata_i == 1)  // DMA_CMD 레지스터 주소와 데이터 확인
            start_reg <= 1'b1;
        else if (done_i)  // DMA 작업이 완료되면 start 신호 리셋
            start_reg <= 1'b0;
    end
    assign start = start_reg;

    // Read
    // ... 기존의 READ 섹션 주석은 그대로 유지 ...

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            rdata <= 32'b0;
        end
        else if(psel_i & ~penable_i & ~pwrite_i) begin  // 읽기 준비 동작
            // 주소에 따른 데이터 할당
            case(paddr_i)
                12'h000: rdata <= src_addr;
                12'h004: rdata <= dst_addr;
                12'h008: rdata <= {16'b0, byte_len};
                // 필요에 따라 더 많은 주소를 위한 케이스 추가 가능
            endcase
        end
    end

    // output assignments
