module DMAC_CFG
(
    input   wire                clk,
    input   wire                rst_n,  // _n means active low

    // AMBA APB interface
    input   wire                psel_i,
    input   wire                penable_i,
    input   wire    [11:0]      paddr_i,
    input   wire                pwrite_i,
    input   wire    [31:0]      pwdata_i,
    output  reg                 pready_o,
    output  reg     [31:0]      prdata_o,
    output  reg                 pslverr_o,

    // configuration registers
    output  reg     [31:0]      src_addr_o,
    output  reg     [31:0]      dst_addr_o,
    output  reg     [15:0]      byte_len_o,
    output  wire                start_o,
    input   wire                done_i
);

    // Configuration register to read/write
    reg     [31:0]              src_addr;
    reg     [31:0]              dst_addr;
    reg     [15:0]              byte_len;
    reg                         start_reg;

    //----------------------------------------------------------
    // Write
    //----------------------------------------------------------
    wire    wren;
    assign  wren = psel_i & penable_i & pwrite_i; // Write enable signal

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            src_addr <= 32'b0;
            dst_addr <= 32'b0;
            byte_len <= 16'b0;
            start_reg <= 1'b0;
        end
        else if (wren) begin
            case (paddr_i)
                12'h000: src_addr <= pwdata_i;
                12'h004: dst_addr <= pwdata_i;
                12'h008: byte_len <= pwdata_i[15:0];
                12'h00C: start_reg <= pwdata_i[0]; // Assuming DMA_CMD register is at 0x00C
            endcase
        end
    end

    //----------------------------------------------------------
    // Read
    //----------------------------------------------------------
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            rdata <= 32'b0;
        end
        else if (psel_i & !penable_i & !pwrite_i) begin // Setup cycle for read
            case (paddr_i)
                12'h000: rdata <= src_addr;
                12'h004: rdata <= dst_addr;
                12'h008: rdata <= {16'b0, byte_len};
                // Additional cases can be added as needed
            endcase
        end
    end

    // Output assignments
    assign pready_o = 1'b1; // Always ready
    assign prdata_o = rdata; // Data read from the configuration registers
    assign pslverr_o = 1'b0; // No slave error
    assign src_addr_o = src_addr;
    assign dst_addr_o = dst_addr;
